import React from "react";

// Lojistik iç sistemi ana sayfası – yalın, örneksiz, yalnızca istenen bölümler
// Ek kütüphane yok. Varsayılan olarak veri göstermiyor; props ile veriyi sen besle.

export default function AnaSayfa({
    kpi, // { bugunTalep, bekleyenTeslimat, buAyGelir, buAyGider, net }
    hareketler = [], // Son gelir-gider hareketleri [{tarih, tur, aciklama, tutar, durum}]
    talepler = [], // Aktif talepler/tedarik [{no, musteri, rota, kapasite, durum}]
    onYeniGelir,
    onYeniGider,
    onYeniTalep,
    onYeniTedarik,
    onTumTalepler,
}) {
    return (
        <div className="root">
            <style>{`
        :root{ --bg:#f7f8fb; --card:#fff; --text:#0f172a; --muted:#4b5563; --line:#e5e7eb; --brand:#2563eb; }
        .root{ background:var(--bg); color:var(--text); min-height:100dvh; }
        .container{ max-width:1200px; margin:0 auto; padding:20px; }
        .top{ position:sticky; top:0; background:rgba(255,255,255,.8); backdrop-filter:blur(8px); border-bottom:1px solid var(--line); z-index:10; }
        .top-in{ display:flex; gap:16px; align-items:center; justify-content:space-between; padding:10px 20px; }
        .brand{ font-weight:800; }
        .nav{ display:flex; gap:12px; }
        .nav a{ text-decoration:none; color:#374151; padding:6px 10px; border-radius:10px; }
        .nav a:hover{ background:#eef2ff; color:var(--brand); }

        .hero{ display:grid; grid-template-columns:1.1fr .9fr; gap:16px; margin:18px auto; }
        @media(max-width:960px){ .hero{ grid-template-columns:1fr; } }
        .panel{ background:var(--card); border:1px solid var(--line); border-radius:16px; box-shadow:0 6px 20px rgba(2,6,23,.04); }
        .p16{ padding:16px; }
        .title{ font-size:28px; font-weight:800; margin:0; }
        .sub{ color:var(--muted); margin:6px 0 0; }
        .actions{ display:flex; flex-wrap:wrap; gap:8px; margin-top:12px; }
        .btn{ appearance:none; border:1px solid var(--line); background:#fff; padding:10px 12px; border-radius:10px; font-weight:600; cursor:pointer; }
        .btn.primary{ background:var(--brand); color:#fff; border-color:var(--brand); }
        .btn:disabled{ opacity:.6; cursor:not-allowed; }

        .kpis{ display:grid; grid-template-columns:repeat(4,1fr); gap:10px; margin-top:12px; }
        @media(max-width:900px){ .kpis{ grid-template-columns:repeat(2,1fr); } }
        .kpi{ background:var(--card); border:1px solid var(--line); border-radius:12px; padding:12px; }
        .kpi h4{ font-size:12px; color:#64748b; margin:0 0 6px; font-weight:600; }
        .kpi strong{ font-size:20px; }

        .grid{ display:grid; grid-template-columns:1.1fr .9fr; gap:16px; margin-top:16px; }
        @media(max-width:1000px){ .grid{ grid-template-columns:1fr; } }
        .table{ width:100%; border-collapse:separate; border-spacing:0; font-size:14px; }
        .table th, .table td{ padding:10px 12px; border-bottom:1px solid var(--line); text-align:left; }
        .table thead th{ font-size:12px; color:#64748b; text-transform:uppercase; letter-spacing:.06em; background:#f8fafc; }
        .empty{ color:#9aa3af; padding:14px; text-align:center; }
        footer{ color:#6b7280; font-size:13px; padding:24px 20px; }
      `}</style>

            {/* Üst bar */}
            <div className="top">
                <div className="top-in container">
                    <div className="brand">Lojistik Portal</div>
                    <nav className="nav">
                        <a href="#gelirgider">Gelir‑Gider</a>
                        <a href="#talep">Talepler</a>
                        <a href="#tedarik">Tedarik</a>
                        <a href="#dashboard">Dashboard</a>
                    </nav>
                </div>
            </div>

            {/* Kahraman alanı + kısayollar */}
            <main className="container">
                <section className="hero">
                    <div className="panel p16">
                        <h1 className="title">Operasyon Özetiniz</h1>
                        <p className="sub">Gelir‑gider, talep‑tedarik ve teslimat süreçleri.</p>
                        <div className="actions" role="group" aria-label="Hızlı işlemler">
                            <button className="btn primary" onClick={onYeniGelir} disabled={!onYeniGelir}>Yeni Gelir</button>
                            <button className="btn" onClick={onYeniGider} disabled={!onYeniGider}>Yeni Gider</button>
                            <button className="btn" onClick={onYeniTalep} disabled={!onYeniTalep}>Talep Oluştur</button>
                            <button className="btn" onClick={onYeniTedarik} disabled={!onYeniTedarik}>Tedarik Kaydı</button>
                        </div>

                        {/* KPI'lar (veri yoksa gösterim yapma) */}
                        {kpi && (
                            <div className="kpis" style={{ marginTop: 12 }}>
                                <div className="kpi"><h4>Bugünkü Talepler</h4><strong>{safe(kpi.bugunTalep)}</strong></div>
                                <div className="kpi"><h4>Bekleyen Teslimat</h4><strong>{safe(kpi.bekleyenTeslimat)}</strong></div>
                                <div className="kpi"><h4>Bu Ay Gelir</h4><strong>{formatTL(kpi.buAyGelir)}</strong></div>
                                <div className="kpi"><h4>Bu Ay Gider</h4><strong>{formatTL(kpi.buAyGider)}</strong></div>
                            </div>
                        )}
                    </div>

                    <div className="panel p16" aria-label="Dashboard alanı">
                        {/* Buraya grafik/harita bileşenlerini sen ekleyeceksin */}
                        <div className="empty">Dashboard için bileşen yer tutucu.</div>
                    </div>
                </section>

                {/* Tablolar – veri yoksa boş durum göster */}
                <section className="grid">
                    <div className="panel p16" id="gelirgider">
                        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 8 }}>
                            <h3 style={{ margin: 0 }}>Son Gelir‑Gider Hareketleri</h3>
                            <div style={{ display: 'flex', gap: 8 }}>
                                <button className="btn" onClick={onYeniGelir} disabled={!onYeniGelir}>Gelir</button>
                                <button className="btn" onClick={onYeniGider} disabled={!onYeniGider}>Gider</button>
                            </div>
                        </div>
                        {hareketler.length === 0 ? (
                            <div className="empty">Kayıt yok.</div>
                        ) : (
                            <table className="table">
                                <thead>
                                    <tr><th>Tarih</th><th>Tür</th><th>Açıklama</th><th>Tutar</th><th>Durum</th></tr>
                                </thead>
                                <tbody>
                                    {hareketler.map((r, i) => (
                                        <tr key={i}><td>{r.tarih}</td><td>{r.tur}</td><td>{r.aciklama}</td><td>{formatTL(r.tutar)}</td><td>{r.durum}</td></tr>
                                    ))}
                                </tbody>
                            </table>
                        )}
                    </div>

                    <div className="panel p16" id="talep">
                        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 8 }}>
                            <h3 style={{ margin: 0 }}>Aktif Talepler / Tedarik</h3>
                            <button className="btn" onClick={onTumTalepler} disabled={!onTumTalepler}>Tüm Talepler</button>
                        </div>
                        {talepler.length === 0 ? (
                            <div className="empty">Kayıt yok.</div>
                        ) : (
                            <table className="table">
                                <thead>
                                    <tr><th>Talep No</th><th>Müşteri</th><th>Çıkış → Varış</th><th>Kapasite</th><th>Durum</th></tr>
                                </thead>
                                <tbody>
                                    {talepler.map((t, i) => (
                                        <tr key={i}><td>{t.no}</td><td>{t.musteri}</td><td>{t.rota}</td><td>{t.kapasite}</td><td>{t.durum}</td></tr>
                                    ))}
                                </tbody>
                            </table>
                        )}
                    </div>
                </section>
            </main>

            <footer className="container">© {new Date().getFullYear()} Lojistik Portal</footer>
        </div>
    );
}

// -------- Helpers --------
function formatTL(n) { if (n == null) return "—"; try { return n.toLocaleString('tr-TR', { style: 'currency', currency: 'TRY' }); } catch { return `${n} ₺`; } }
function safe(v) { return v == null ? "—" : v; }
